/**
 * User notification preferences model — multi-channel support.
 *
 * Controls how and when notifications are delivered to each user across
 * all supported channels (email, SMS, webhook).
 *
 * DECISION CHANGE (Session 9): Email-Only → Multi-Channel Preferences
 * ====================================================================
 * This model was originally designed with email as the ONLY notification channel
 * (Session 3). With the addition of SMS support (Session 8, see src/adapters/sms.adapter.ts)
 * and the existing webhook adapter, the email-only assumption is NO LONGER VALID.
 *
 * This refactor adds per-channel preference settings:
 * - Email: opt-OUT by default (enabled=true) — preserves backward compatibility.
 * - SMS: opt-IN by default (enabled=false) — SMS is more intrusive, requires explicit opt-in.
 * - Webhook: opt-IN by default (enabled=false) — requires explicit URL configuration.
 *
 * Backward compatibility:
 * - Existing code that only sets `email` preferences continues to work unchanged.
 * - SMS and webhook preferences default to disabled, so no existing behavior changes.
 * - The `isNotificationEnabled()` method in PreferencesService now accepts an optional
 *   channel parameter, defaulting to 'email' for backward compatibility.
 * ====================================================================
 *
 * Preference Lookup:
 * - The NotificationService checks preferences before dispatching event-driven notifications.
 * - If no preferences record exists for a user, all notifications are sent (opt-out model).
 * - Users must explicitly disable categories or a channel's master toggle to suppress notifications.
 * - For SMS and webhook, users must explicitly ENABLE the channel (opt-in model).
 */

/**
 * Email delivery frequency options.
 * Controls how notifications are batched for email delivery.
 *
 * - 'immediate': Send emails as events occur (default)
 * - 'daily_digest': Batch notifications into a single daily summary email
 * - 'weekly_digest': Batch notifications into a single weekly summary email
 */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest';

/**
 * Notification categories that users can subscribe to or unsubscribe from.
 * Each category corresponds to one or more domain events in the system.
 *
 * Mapping to domain events:
 * - 'order_confirmations'   → order:created event
 * - 'order_status_updates'  → order:status-changed event
 * - 'account_updates'       → user:updated event (future use)
 * - 'promotions'            → promotional campaigns (future use)
 */
export type NotificationCategory =
  | 'order_confirmations'
  | 'order_status_updates'
  | 'account_updates'
  | 'promotions';

/**
 * Complete list of all available notification categories.
 * Used for initializing default preferences (subscribe to all).
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationCategory[] = [
  'order_confirmations',
  'order_status_updates',
  'account_updates',
  'promotions',
];

/**
 * Notification channel identifiers that support per-channel preferences.
 * Matches the channels that have adapters registered with NotificationService.
 */
export type PreferenceChannel = 'email' | 'sms' | 'webhook';

/**
 * Email-specific notification settings.
 */
export interface EmailPreferences {
  /** Master toggle for all email notifications. When false, no emails are sent. */
  enabled: boolean;
  /** How frequently email notifications should be delivered. */
  frequency: EmailFrequency;
  /**
   * Which notification categories the user is subscribed to.
   * Only categories present in this array will generate email notifications.
   */
  subscribedCategories: NotificationCategory[];
}

/**
 * SMS-specific notification settings.
 *
 * Unlike email, SMS has no frequency batching — all SMS notifications are immediate.
 * SMS is opt-in by default (enabled=false) because it is a more intrusive channel.
 */
export interface SmsPreferences {
  /** Master toggle for all SMS notifications. When false, no SMS messages are sent. */
  enabled: boolean;
  /**
   * Which notification categories the user is subscribed to for SMS.
   * Only categories present in this array will generate SMS notifications.
   */
  subscribedCategories: NotificationCategory[];
}

/**
 * Webhook-specific notification settings.
 *
 * Webhook notifications are opt-in by default (enabled=false) and require
 * a configured URL to receive HTTP POST payloads.
 */
export interface WebhookPreferences {
  /** Master toggle for all webhook notifications. When false, no webhooks are sent. */
  enabled: boolean;
  /**
   * Which notification categories the user is subscribed to for webhook delivery.
   * Only categories present in this array will generate webhook notifications.
   */
  subscribedCategories: NotificationCategory[];
  /** The URL to send webhook payloads to. Required when enabled is true. */
  url?: string;
}

/**
 * Full user notification preferences record.
 *
 * One record per user. The `id` field matches the user's ID, establishing
 * a 1:1 relationship between users and their preferences.
 *
 * Supports per-channel settings for email, SMS, and webhook.
 * SMS and webhook are optional fields — when absent, their defaults apply
 * (both disabled by default, preserving backward compatibility).
 */
export interface UserPreferences {
  /** Unique identifier — matches the userId this record belongs to. */
  id: string;
  /** The user this preferences record belongs to (same as id). */
  userId: string;
  /** Email notification settings. */
  email: EmailPreferences;
  /** SMS notification settings. Optional — defaults to disabled if absent. */
  sms: SmsPreferences;
  /** Webhook notification settings. Optional — defaults to disabled if absent. */
  webhook: WebhookPreferences;
  /** When this preferences record was created. */
  createdAt: Date;
  /** When this preferences record was last updated. */
  updatedAt: Date;
}

/**
 * Input for creating user preferences.
 * Only userId is required; all channel settings default to their respective defaults.
 */
export interface CreateUserPreferencesInput {
  /** The user ID to create preferences for. */
  userId: string;
  /** Partial email preferences — missing fields use defaults. */
  email?: Partial<EmailPreferences>;
  /** Partial SMS preferences — missing fields use defaults. */
  sms?: Partial<SmsPreferences>;
  /** Partial webhook preferences — missing fields use defaults. */
  webhook?: Partial<WebhookPreferences>;
}

/**
 * Input for updating user preferences.
 * All fields are optional — only provided fields are updated.
 */
export interface UpdateUserPreferencesInput {
  /** Partial email preferences — only provided fields are updated. */
  email?: Partial<EmailPreferences>;
  /** Partial SMS preferences — only provided fields are updated. */
  sms?: Partial<SmsPreferences>;
  /** Partial webhook preferences — only provided fields are updated. */
  webhook?: Partial<WebhookPreferences>;
}

/**
 * Default email preferences for new users.
 * All categories are subscribed and immediate delivery is enabled.
 * Email is opt-OUT: enabled by default.
 */
export const DEFAULT_EMAIL_PREFERENCES: Readonly<EmailPreferences> = {
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

/**
 * Default SMS preferences for new users.
 * SMS is opt-IN: disabled by default (more intrusive channel).
 * All categories are subscribed so that enabling SMS immediately delivers all categories.
 */
export const DEFAULT_SMS_PREFERENCES: Readonly<SmsPreferences> = {
  enabled: false,
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

/**
 * Default webhook preferences for new users.
 * Webhook is opt-IN: disabled by default (requires URL configuration).
 * All categories are subscribed so that enabling webhook immediately delivers all categories.
 */
export const DEFAULT_WEBHOOK_PREFERENCES: Readonly<WebhookPreferences> = {
  enabled: false,
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  url: undefined,
};

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 * Each user has at most one preferences record (1:1 relationship).
 * The record's `id` matches the `userId` it belongs to.
 *
 * Supports multi-channel preferences (email, SMS, webhook).
 * SMS and webhook fields are serialized alongside email fields,
 * with defaults applied during deserialization for backward compatibility.
 *
 * Depends on the Database utility layer for storage.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type {
  UserPreferences,
  NotificationCategory,
  EmailFrequency,
} from '../models/user-preferences.js';
import {
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
} from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as EmailFrequency,
        subscribedCategories: JSON.parse(
          record['emailSubscribedCategories'] as string,
        ) as NotificationCategory[],
      },
      sms: {
        enabled: (record['smsEnabled'] as boolean | undefined) ?? DEFAULT_SMS_PREFERENCES.enabled,
        subscribedCategories: record['smsSubscribedCategories']
          ? (JSON.parse(record['smsSubscribedCategories'] as string) as NotificationCategory[])
          : [...DEFAULT_SMS_PREFERENCES.subscribedCategories],
      },
      webhook: {
        enabled: (record['webhookEnabled'] as boolean | undefined) ?? DEFAULT_WEBHOOK_PREFERENCES.enabled,
        subscribedCategories: record['webhookSubscribedCategories']
          ? (JSON.parse(record['webhookSubscribedCategories'] as string) as NotificationCategory[])
          : [...DEFAULT_WEBHOOK_PREFERENCES.subscribedCategories],
        url: (record['webhookUrl'] as string | undefined) ?? undefined,
      },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailSubscribedCategories: JSON.stringify(entity.email.subscribedCategories),
      smsEnabled: entity.sms.enabled,
      smsSubscribedCategories: JSON.stringify(entity.sms.subscribedCategories),
      webhookEnabled: entity.webhook.enabled,
      webhookSubscribedCategories: JSON.stringify(entity.webhook.subscribedCategories),
      webhookUrl: entity.webhook.url ?? '',
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   * Since id === userId, this is equivalent to findById.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    return this.findById(userId);
  }
}

/**
 * Preferences service — business logic for managing user notification preferences.
 *
 * Provides CRUD operations for user notification preferences, including
 * default initialization and partial updates. Supports per-channel settings
 * for email, SMS, and webhook channels.
 *
 * Opt-out vs opt-in model:
 * - Email: opt-OUT — enabled by default. New users receive all email notifications
 *   until they explicitly configure preferences.
 * - SMS: opt-IN — disabled by default. Users must explicitly enable SMS.
 * - Webhook: opt-IN — disabled by default. Users must explicitly enable webhook.
 *
 * Depends on:
 * - PreferencesRepository (data layer) for persistence
 * - EventBus (event system) for publishing preference lifecycle events
 *
 * Usage by other services:
 * - NotificationService uses isChannelEnabledForCategory() to check whether a notification
 *   should be sent on a specific channel before dispatching to an adapter.
 * - NotificationService uses getEnabledChannelsForCategory() to determine all channels
 *   to dispatch to for event-driven notifications.
 */

import type {
  UserPreferences,
  CreateUserPreferencesInput,
  UpdateUserPreferencesInput,
  NotificationCategory,
  PreferenceChannel,
} from '../models/user-preferences.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
} from '../models/user-preferences.js';
import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type { EventBus } from '../events/event-bus.js';
import { Logger } from '../utils/logger.js';
import {
  validatePreferencesNotExist,
  validatePreferencesExist,
} from '../validators/preferences.validator.js';

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(
    private preferencesRepository: PreferencesRepository,
    private eventBus: EventBus,
  ) {}

  // ---------------------------------------------------------------------------
  // Preferences CRUD
  // ---------------------------------------------------------------------------

  /**
   * Create notification preferences for a user.
   *
   * Merges provided settings with defaults so callers only need to
   * specify the fields they want to override. Supports email, SMS,
   * and webhook channel preferences.
   *
   * @param input - User ID and optional partial channel preferences.
   * @returns The created UserPreferences record with all defaults applied.
   * @throws Error if preferences already exist for this user.
   */
  createPreferences(input: CreateUserPreferencesInput): UserPreferences {
    this.logger.info(`Creating preferences for user: ${input.userId}`);

    // Check for existing preferences
    const existing = this.preferencesRepository.findByUserId(input.userId);
    validatePreferencesNotExist(existing, input.userId);

    const now = new Date();
    const preferences: UserPreferences = {
      id: input.userId,
      userId: input.userId,
      email: {
        enabled: input.email?.enabled ?? DEFAULT_EMAIL_PREFERENCES.enabled,
        frequency: input.email?.frequency ?? DEFAULT_EMAIL_PREFERENCES.frequency,
        subscribedCategories:
          input.email?.subscribedCategories ??
          [...DEFAULT_EMAIL_PREFERENCES.subscribedCategories],
      },
      sms: {
        enabled: input.sms?.enabled ?? DEFAULT_SMS_PREFERENCES.enabled,
        subscribedCategories:
          input.sms?.subscribedCategories ??
          [...DEFAULT_SMS_PREFERENCES.subscribedCategories],
      },
      webhook: {
        enabled: input.webhook?.enabled ?? DEFAULT_WEBHOOK_PREFERENCES.enabled,
        subscribedCategories:
          input.webhook?.subscribedCategories ??
          [...DEFAULT_WEBHOOK_PREFERENCES.subscribedCategories],
        url: input.webhook?.url ?? DEFAULT_WEBHOOK_PREFERENCES.url,
      },
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(preferences);
    this.logger.info(`Preferences created for user: ${input.userId}`);

    return preferences;
  }

  /**
   * Get notification preferences for a user.
   *
   * @param userId - The user ID to look up.
   * @returns The user's preferences, or undefined if none are configured.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Update notification preferences for a user.
   *
   * Only provided fields are updated; missing fields retain their current values.
   * Supports partial updates to email, SMS, and webhook preferences.
   *
   * @param userId - The user whose preferences to update.
   * @param input - Partial preference updates to apply.
   * @returns The updated UserPreferences record.
   * @throws Error if no preferences exist for this user.
   */
  updatePreferences(userId: string, input: UpdateUserPreferencesInput): UserPreferences {
    this.logger.info(`Updating preferences for user: ${userId}`);

    const existing = this.preferencesRepository.findByUserId(userId);
    validatePreferencesExist(existing, userId);

    const updatedEmail = {
      enabled: input.email?.enabled ?? existing.email.enabled,
      frequency: input.email?.frequency ?? existing.email.frequency,
      subscribedCategories:
        input.email?.subscribedCategories ?? [...existing.email.subscribedCategories],
    };

    const updatedSms = {
      enabled: input.sms?.enabled ?? existing.sms.enabled,
      subscribedCategories:
        input.sms?.subscribedCategories ?? [...existing.sms.subscribedCategories],
    };

    const updatedWebhook = {
      enabled: input.webhook?.enabled ?? existing.webhook.enabled,
      subscribedCategories:
        input.webhook?.subscribedCategories ?? [...existing.webhook.subscribedCategories],
      url: input.webhook?.url ?? existing.webhook.url,
    };

    const updated = this.preferencesRepository.update(userId, {
      email: updatedEmail,
      sms: updatedSms,
      webhook: updatedWebhook,
      updatedAt: new Date(),
    });

    this.logger.info(`Preferences updated for user: ${userId}`);
    return updated;
  }

  /**
   * Delete notification preferences for a user.
   * After deletion, the user reverts to default behavior (all notifications enabled).
   *
   * @param userId - The user whose preferences to delete.
   * @returns true if preferences were deleted, false if none existed.
   */
  deletePreferences(userId: string): boolean {
    this.logger.info(`Deleting preferences for user: ${userId}`);
    return this.preferencesRepository.delete(userId);
  }

  /**
   * Get or create preferences for a user, ensuring defaults are applied.
   * If no preferences exist, creates a record with default settings.
   *
   * @param userId - The user ID.
   * @returns The user's preferences (existing or newly created with defaults).
   */
  getOrCreatePreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }
    return this.createPreferences({ userId });
  }

  // ---------------------------------------------------------------------------
  // Preference Queries — used by NotificationService
  // ---------------------------------------------------------------------------

  /**
   * Check if a specific notification category is enabled for a user on a given channel.
   *
   * This is the primary method used by NotificationService to decide whether
   * to dispatch a notification on a specific channel. It checks both the
   * channel's master toggle and the category subscription.
   *
   * Returns true (send notification) when:
   * - No preferences exist for the user AND the channel is email (opt-out model for email)
   * - The channel is enabled AND the category is in the subscribed list
   *
   * For backward compatibility, the channel parameter defaults to 'email'.
   *
   * @param userId - The user to check.
   * @param category - The notification category to check.
   * @param channel - The notification channel to check. Defaults to 'email'.
   * @returns true if the notification should be sent on this channel.
   */
  isNotificationEnabled(
    userId: string,
    category: NotificationCategory,
    channel: PreferenceChannel = 'email',
  ): boolean {
    const prefs = this.preferencesRepository.findByUserId(userId);

    // No preferences configured → opt-out model for email (send everything),
    // opt-in model for SMS/webhook (don't send)
    if (!prefs) {
      return channel === 'email';
    }

    const channelPrefs = prefs[channel];

    // Master channel toggle
    if (!channelPrefs.enabled) {
      return false;
    }

    // Category subscription check
    return channelPrefs.subscribedCategories.includes(category);
  }

  /**
   * Check if email notifications are enabled for a user (master toggle only).
   *
   * @param userId - The user to check.
   * @returns true if email is enabled or no preferences exist.
   */
  isEmailEnabled(userId: string): boolean {
    const prefs = this.preferencesRepository.findByUserId(userId);

    // No preferences → default is enabled for email
    if (!prefs) {
      return true;
    }

    return prefs.email.enabled;
  }

  /**
   * Check if SMS notifications are enabled for a user (master toggle only).
   *
   * @param userId - The user to check.
   * @returns true if SMS is enabled. Returns false if no preferences exist (opt-in model).
   */
  isSmsEnabled(userId: string): boolean {
    const prefs = this.preferencesRepository.findByUserId(userId);

    // No preferences → default is disabled for SMS (opt-in)
    if (!prefs) {
      return false;
    }

    return prefs.sms.enabled;
  }

  /**
   * Check if webhook notifications are enabled for a user (master toggle only).
   *
   * @param userId - The user to check.
   * @returns true if webhook is enabled. Returns false if no preferences exist (opt-in model).
   */
  isWebhookEnabled(userId: string): boolean {
    const prefs = this.preferencesRepository.findByUserId(userId);

    // No preferences → default is disabled for webhook (opt-in)
    if (!prefs) {
      return false;
    }

    return prefs.webhook.enabled;
  }

  /**
   * Get all channels that are enabled for a specific notification category.
   *
   * Used by NotificationService to determine which channels to dispatch to
   * for event-driven notifications.
   *
   * @param userId - The user to check.
   * @param category - The notification category.
   * @returns Array of channel names that should receive the notification.
   */
  getEnabledChannelsForCategory(
    userId: string,
    category: NotificationCategory,
  ): PreferenceChannel[] {
    const channels: PreferenceChannel[] = ['email', 'sms', 'webhook'];
    return channels.filter((channel) => this.isNotificationEnabled(userId, category, channel));
  }
}

/**
 * Notification service — the central hub for all notification delivery.
 *
 * ARCHITECTURE: Event-Driven with Adapter Pattern
 * =================================================
 *
 * This service is the SOLE entry point for sending notifications. It:
 * 1. Subscribes to domain events via EventBus (e.g., order:created, order:status-changed).
 * 2. Translates domain events into notification payloads.
 * 3. Checks user notification preferences before dispatching (opt-out/opt-in model).
 * 4. Routes notifications to ALL enabled channels via their NotificationAdapters.
 * 5. Emits notification lifecycle events (notification:sent, notification:failed).
 *
 * Flow:
 *   DomainEvent → EventBus → NotificationService → PreferencesCheck → NotificationAdapter(s) → delivery
 *                                    ↓
 *                              EventBus ← notification:sent / notification:failed
 *
 * Multi-Channel Dispatch (Session 9):
 * - Event-driven notifications now dispatch to ALL channels the user has enabled.
 * - Email is opt-out (enabled by default), SMS and webhook are opt-in (disabled by default).
 * - The public send() method still dispatches to a single channel (caller's choice).
 *
 * Preference Checking:
 * - If a PreferencesService is configured, event-driven notifications are checked
 *   against user preferences before dispatch (per-channel).
 * - If no PreferencesService is configured, only email is sent (backward compatible).
 * - If no preferences exist for a user, email is sent (opt-out), SMS/webhook are not (opt-in).
 * - The public send() method does NOT check preferences — callers are responsible.
 *
 * CONSTRAINTS:
 * - All notifications MUST go through this service — never call adapters directly.
 * - All domain event subscriptions are registered in registerEventHandlers().
 * - All adapters MUST implement the NotificationAdapter interface.
 * - Each NotificationType has at most one registered adapter.
 * - If no adapter is registered for a channel, the notification is still recorded in-memory.
 *
 * Depends on:
 * - EventBus (event system) for ALL event subscriptions — no other patterns allowed.
 * - NotificationAdapter implementations for actual delivery.
 * - PreferencesService (optional) for checking user notification preferences.
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationType,
  NotificationPayload,
  CreateNotificationInput,
} from '../models/notification.js';
import type { NotificationCategory } from '../models/user-preferences.js';
import type { PreferencesService } from './preferences.service.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter (for testing). */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationType, NotificationAdapter> = new Map();
  private preferencesService?: PreferencesService;

  constructor(
    private eventBus: EventBus,
    preferencesService?: PreferencesService,
  ) {
    this.preferencesService = preferencesService;
    this.registerEventHandlers();
  }

  // ---------------------------------------------------------------------------
  // Preferences Integration
  // ---------------------------------------------------------------------------

  /**
   * Set or replace the preferences service used for notification filtering.
   * When set, event-driven notifications will be checked against user preferences
   * before dispatching.
   *
   * @param service - The preferences service to use, or undefined to disable checking.
   */
  setPreferencesService(service: PreferencesService | undefined): void {
    this.preferencesService = service;
    this.logger.info(
      service
        ? 'Preferences service configured — notifications will respect user preferences'
        : 'Preferences service removed — all notifications will be sent',
    );
  }

  // ---------------------------------------------------------------------------
  // Adapter Registration
  // ---------------------------------------------------------------------------

  /**
   * Register a notification adapter for a specific channel.
   * Only one adapter per channel is allowed — registering a new adapter
   * for an existing channel replaces the previous one.
   *
   * @param adapter - The adapter to register. Must implement NotificationAdapter.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registering adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Unregister the adapter for a specific channel.
   *
   * @param channel - The channel whose adapter should be removed.
   * @returns true if an adapter was removed, false if none was registered.
   */
  unregisterAdapter(channel: NotificationType): boolean {
    this.logger.info(`Unregistering adapter for channel: ${channel}`);
    return this.adapters.delete(channel);
  }

  /**
   * Get the adapter registered for a specific channel.
   *
   * @param channel - The channel to look up.
   * @returns The registered adapter, or undefined if none is registered.
   */
  getAdapter(channel: NotificationType): NotificationAdapter | undefined {
    return this.adapters.get(channel);
  }

  /**
   * Get all registered adapter channels.
   */
  getRegisteredChannels(): NotificationType[] {
    return [...this.adapters.keys()];
  }

  // ---------------------------------------------------------------------------
  // Notification Sending (public API)
  // ---------------------------------------------------------------------------

  /**
   * Send a notification through the appropriate adapter.
   * This is the primary public method for dispatching notifications programmatically.
   *
   * Creates a Notification record, dispatches it to the adapter,
   * and emits lifecycle events (notification:sent or notification:failed).
   *
   * @param input - The notification content and delivery channel.
   * @returns The created Notification record with final status.
   */
  async send(input: CreateNotificationInput): Promise<Notification> {
    const notification = this.createNotificationRecord(input);
    this.notifications.push(notification);

    this.logger.info(
      `Notification ${notification.id} queued: channel=${input.channel}, recipient=${input.recipient}`,
    );

    // Emit requested event for audit/analytics
    await this.eventBus.emit({
      type: 'notification:requested',
      notification,
      timestamp: new Date(),
    });

    // Look up the adapter for this channel
    const adapter = this.adapters.get(input.channel);

    if (!adapter) {
      notification.status = 'failed';
      notification.errorMessage = `No adapter registered for channel: ${input.channel}`;
      this.logger.warn(notification.errorMessage);

      await this.eventBus.emit({
        type: 'notification:failed',
        notification,
        channel: input.channel,
        errorMessage: notification.errorMessage,
        timestamp: new Date(),
      });

      return notification;
    }

    if (!adapter.isAvailable()) {
      notification.status = 'failed';
      notification.errorMessage = `Adapter for channel "${input.channel}" is not available`;
      this.logger.warn(notification.errorMessage);

      await this.eventBus.emit({
        type: 'notification:failed',
        notification,
        channel: input.channel,
        errorMessage: notification.errorMessage,
        timestamp: new Date(),
      });

      return notification;
    }

    // Build the payload for the adapter
    const payload: NotificationPayload = {
      recipient: input.recipient,
      subject: input.subject,
      body: input.body,
      channel: input.channel,
      priority: input.priority ?? 'normal',
      metadata: input.metadata,
    };

    // Dispatch to the adapter
    const result = await adapter.send(payload);

    if (result.success) {
      notification.status = 'sent';
      notification.sentAt = new Date();
      this.logger.info(`Notification ${notification.id} sent successfully via ${input.channel}`);

      await this.eventBus.emit({
        type: 'notification:sent',
        notification,
        channel: input.channel,
        timestamp: new Date(),
      });
    } else {
      notification.status = 'failed';
      notification.errorMessage = result.errorMessage ?? 'Unknown delivery error';
      this.logger.error(
        `Notification ${notification.id} failed via ${input.channel}: ${notification.errorMessage}`,
      );

      await this.eventBus.emit({
        type: 'notification:failed',
        notification,
        channel: input.channel,
        errorMessage: notification.errorMessage,
        timestamp: new Date(),
      });
    }

    return notification;
  }

  // ---------------------------------------------------------------------------
  // Event Handlers — translate domain events into notifications
  // ---------------------------------------------------------------------------

  /**
   * Register EventBus handlers for all domain events that trigger notifications.
   *
   * CONSTRAINT: ALL event subscriptions MUST be registered here.
   * This is the single place where domain events are wired to notifications.
   * To add a new event-triggered notification, add a handler in this method.
   */
  private registerEventHandlers(): void {
    // Order created → send confirmation to the user
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    // Order status changed → notify user of the update (now via EventBus, not CallbackRegistry)
    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   * Dispatches to all enabled channels based on user preferences.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Processing order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.dispatchMultiChannelNotification({
      userId: event.user.id,
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      category: 'order_confirmations',
    });
  }

  /**
   * Handle order status change — notify user of update.
   * Dispatches to all enabled channels based on user preferences.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Processing status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    this.dispatchMultiChannelNotification({
      userId: event.order.userId,
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      category: 'order_status_updates',
    });
  }

  // ---------------------------------------------------------------------------
  // Preference Checking
  // ---------------------------------------------------------------------------

  /**
   * Check whether a notification should be sent for a given user, category, and channel.
   *
   * Returns true (send notification) when:
   * - No PreferencesService is configured AND channel is email (backward compatibility)
   * - PreferencesService reports the channel+category is enabled for this user
   *
   * @param userId - The user to check preferences for.
   * @param category - The notification category being sent.
   * @param channel - The notification channel to check.
   * @returns true if the notification should proceed, false to suppress.
   */
  private shouldSendNotification(
    userId: string,
    category: NotificationCategory,
    channel: NotificationType,
  ): boolean {
    if (!this.preferencesService) {
      // No preferences service → backward compat: only send email
      return channel === 'email';
    }

    // Map NotificationType to PreferenceChannel for the check.
    // 'in_app' has no preference support yet — default to sending.
    if (channel === 'in_app') {
      return true;
    }

    return this.preferencesService.isNotificationEnabled(userId, category, channel);
  }

  /**
   * Get all channels that should receive a notification for a user and category.
   *
   * @param userId - The user to check preferences for.
   * @param category - The notification category.
   * @returns Array of channel names that should receive the notification.
   */
  private getChannelsToDispatch(
    userId: string,
    category: NotificationCategory,
  ): NotificationType[] {
    if (!this.preferencesService) {
      // No preferences service → backward compat: only email
      return ['email'];
    }

    return this.preferencesService.getEnabledChannelsForCategory(userId, category);
  }

  // ---------------------------------------------------------------------------
  // Multi-Channel Dispatch — creates records for event-triggered notifications
  // ---------------------------------------------------------------------------

  /**
   * Dispatch a notification to all enabled channels for a user.
   *
   * This replaces the old email-only dispatchInternalNotification method.
   * For each enabled channel, it creates a Notification record and attempts
   * delivery through the registered adapter.
   *
   * Backward compatibility:
   * - Without a PreferencesService, only email channel is used.
   * - Without preferences for a user, email is sent (opt-out), SMS/webhook are not (opt-in).
   */
  private dispatchMultiChannelNotification(params: {
    userId: string;
    recipient: string;
    subject: string;
    body: string;
    category: NotificationCategory;
  }): void {
    const channels = this.getChannelsToDispatch(params.userId, params.category);

    if (channels.length === 0) {
      this.logger.info(
        `All notifications suppressed for user ${params.userId}: no channels enabled for ${params.category}`,
      );
      return;
    }

    for (const channel of channels) {
      this.dispatchToChannel({
        recipient: params.recipient,
        subject: params.subject,
        body: params.body,
        channel,
      });
    }
  }

  /**
   * Dispatch a notification to a single channel.
   * Creates a record in-memory and attempts delivery through the adapter if available.
   */
  private dispatchToChannel(params: {
    recipient: string;
    subject: string;
    body: string;
    channel: NotificationType;
  }): void {
    const notification: Notification = {
      id: generateNotificationId(),
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      channel: params.channel,
      priority: 'normal',
      status: 'sent',
      createdAt: new Date(),
      sentAt: new Date(),
    };

    this.notifications.push(notification);
    this.logger.info(
      `Notification sent: ${notification.id} to ${params.recipient} via ${params.channel}`,
    );

    // If an adapter is registered for this channel, also dispatch through it
    const adapter = this.adapters.get(params.channel);
    if (adapter?.isAvailable()) {
      const payload: NotificationPayload = {
        recipient: params.recipient,
        subject: params.subject,
        body: params.body,
        channel: params.channel,
        priority: 'normal',
      };
      adapter.send(payload).catch((err: unknown) => {
        const msg = err instanceof Error ? err.message : 'Unknown error';
        this.logger.error(`Adapter delivery error (${params.channel}): ${msg}`);
      });
    }
  }

  // ---------------------------------------------------------------------------
  // Notification Query API
  // ---------------------------------------------------------------------------

  /**
   * Get all notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }

  // ---------------------------------------------------------------------------
  // Private Helpers
  // ---------------------------------------------------------------------------

  /**
   * Create a new Notification record from input.
   */
  private createNotificationRecord(input: CreateNotificationInput): Notification {
    return {
      id: generateNotificationId(),
      recipient: input.recipient,
      subject: input.subject,
      body: input.body,
      channel: input.channel,
      priority: input.priority ?? 'normal',
      status: 'pending',
      createdAt: new Date(),
      metadata: input.metadata,
    };
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
