      expect(prefs.email.subscribedCategories).toEqual(['order_confirmations']);
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
    });

    it('should create preferences with all custom email settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-0001',
