        sms: {
          enabled: true,
          subscribedCategories: ['order_confirmations'],
        },
      });

      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.sms.subscribedCategories).toEqual(['order_confirmations']);
    });

    it('should create preferences with webhook enabled and URL', () => {
