        webhook: {
          enabled: true,
          url: 'https://example.com/webhook',
        },
      });

      expect(prefs.webhook.enabled).toBe(true);
      expect(prefs.webhook.url).toBe('https://example.com/webhook');
      expect(prefs.webhook.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should create preferences with all channels configured', () => {
      const prefs = service.createPreferences({
        userId: 'user-0001',
        email: { enabled: true, frequency: 'daily_digest' },
        sms: { enabled: true, subscribedCategories: ['order_confirmations'] },
