      expect(prefs.email.frequency).toBe('daily_digest');
      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.sms.subscribedCategories).toEqual(['order_confirmations']);
      expect(prefs.webhook.enabled).toBe(true);
      expect(prefs.webhook.url).toBe('https://example.com/hook');
      expect(prefs.webhook.subscribedCategories).toEqual(['order_status_updates']);
    });

    it('should reject duplicate preferences for same user', () => {
      service.createPreferences({ userId: 'user-0001' });

      expect(() => {
        service.createPreferences({ userId: 'user-0001' });
      }).toThrow('Preferences already exist for user: user-0001');
