        userId: 'user-0001',
        sms: {
          enabled: true,
          subscribedCategories: ['order_confirmations'],
        },
      });

      expect(service.isNotificationEnabled('user-0001', 'order_confirmations', 'sms')).toBe(true);
      expect(service.isNotificationEnabled('user-0001', 'order_status_updates', 'sms')).toBe(false);
    });

    it('should check webhook channel when specified', () => {
      service.createPreferences({
        userId: 'user-0001',
        webhook: {
          enabled: true,
          subscribedCategories: ['order_status_updates'],
        },
      });

      expect(service.isNotificationEnabled('user-0001', 'order_status_updates', 'webhook')).toBe(true);
      expect(service.isNotificationEnabled('user-0001', 'order_confirmations', 'webhook')).toBe(false);
    });

    it('should return false for SMS when disabled even with category subscribed', () => {
      service.createPreferences({
        userId: 'user-0001',
        sms: {
          enabled: false,
          subscribedCategories: ALL_NOTIFICATION_CATEGORIES,
        },
      });

      expect(service.isNotificationEnabled('user-0001', 'order_confirmations', 'sms')).toBe(false);
    });
  });

  // ---------------------------------------------------------------------------
  // isEmailEnabled
  // ---------------------------------------------------------------------------

  describe('isEmailEnabled', () => {
    it('should return true when no preferences exist', () => {
      expect(service.isEmailEnabled('user-0001')).toBe(true);
    });

    it('should return true when email is enabled', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { enabled: true },
      });

      expect(service.isEmailEnabled('user-0001')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { enabled: false },
      });

      expect(service.isEmailEnabled('user-0001')).toBe(false);
    });
  });

  // ---------------------------------------------------------------------------
  // isSmsEnabled
  // ---------------------------------------------------------------------------

  describe('isSmsEnabled', () => {
    it('should return false when no preferences exist (opt-in model)', () => {
      expect(service.isSmsEnabled('user-0001')).toBe(false);
    });

    it('should return true when SMS is enabled', () => {
      service.createPreferences({
        userId: 'user-0001',
        sms: { enabled: true },
      });

      expect(service.isSmsEnabled('user-0001')).toBe(true);
    });

    it('should return false when SMS is disabled', () => {
      service.createPreferences({
        userId: 'user-0001',
        sms: { enabled: false },
      });

      expect(service.isSmsEnabled('user-0001')).toBe(false);
    });
  });

  // ---------------------------------------------------------------------------
  // isWebhookEnabled
  // ---------------------------------------------------------------------------

  describe('isWebhookEnabled', () => {
    it('should return false when no preferences exist (opt-in model)', () => {
      expect(service.isWebhookEnabled('user-0001')).toBe(false);
    });

    it('should return true when webhook is enabled', () => {
      service.createPreferences({
        userId: 'user-0001',
        webhook: { enabled: true },
      });

      expect(service.isWebhookEnabled('user-0001')).toBe(true);
    });

    it('should return false when webhook is disabled', () => {
      service.createPreferences({
        userId: 'user-0001',
        webhook: { enabled: false },
      });

      expect(service.isWebhookEnabled('user-0001')).toBe(false);
    });
  });

  // ---------------------------------------------------------------------------
  // getEnabledChannelsForCategory
  // ---------------------------------------------------------------------------

  describe('getEnabledChannelsForCategory', () => {
    it('should return only email when no preferences exist', () => {
      const channels = service.getEnabledChannelsForCategory('user-0001', 'order_confirmations');
      expect(channels).toEqual(['email']);
    });

    it('should return email when email is enabled for category', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { enabled: true, subscribedCategories: ['order_confirmations'] },
      });

      const channels = service.getEnabledChannelsForCategory('user-0001', 'order_confirmations');
      expect(channels).toContain('email');
    });

    it('should return email and sms when both are enabled for category', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { enabled: true, subscribedCategories: ['order_confirmations'] },
        sms: { enabled: true, subscribedCategories: ['order_confirmations'] },
      });

      const channels = service.getEnabledChannelsForCategory('user-0001', 'order_confirmations');
      expect(channels).toContain('email');
      expect(channels).toContain('sms');
      expect(channels).toHaveLength(2);
    });

    it('should return all three channels when all enabled for category', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { enabled: true },
        sms: { enabled: true },
        webhook: { enabled: true },
      });

      const channels = service.getEnabledChannelsForCategory('user-0001', 'order_confirmations');
      expect(channels).toContain('email');
      expect(channels).toContain('sms');
      expect(channels).toContain('webhook');
      expect(channels).toHaveLength(3);
    });

    it('should return empty array when all channels are disabled', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { enabled: false },
        sms: { enabled: false },
        webhook: { enabled: false },
      });

      const channels = service.getEnabledChannelsForCategory('user-0001', 'order_confirmations');
      expect(channels).toEqual([]);
    });

    it('should respect per-channel category subscriptions', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { enabled: true, subscribedCategories: ['order_confirmations'] },
        sms: { enabled: true, subscribedCategories: ['order_status_updates'] },
      });

      const confirmChannels = service.getEnabledChannelsForCategory('user-0001', 'order_confirmations');
      expect(confirmChannels).toEqual(['email']);

      const statusChannels = service.getEnabledChannelsForCategory('user-0001', 'order_status_updates');
      expect(statusChannels).toEqual(['sms']);
    });
  });

  // ---------------------------------------------------------------------------
  // DEFAULT_EMAIL_PREFERENCES constant
  // ---------------------------------------------------------------------------

  describe('DEFAULT_EMAIL_PREFERENCES', () => {
    it('should have email enabled by default', () => {
      expect(DEFAULT_EMAIL_PREFERENCES.enabled).toBe(true);
    });

    it('should have immediate frequency by default', () => {
      expect(DEFAULT_EMAIL_PREFERENCES.frequency).toBe('immediate');
    });

    it('should subscribe to all categories by default', () => {
      expect(DEFAULT_EMAIL_PREFERENCES.subscribedCategories).toEqual(
        ALL_NOTIFICATION_CATEGORIES,
      );
    });
  });

  // ---------------------------------------------------------------------------
  // DEFAULT_SMS_PREFERENCES constant
  // ---------------------------------------------------------------------------

  describe('DEFAULT_SMS_PREFERENCES', () => {
    it('should have SMS disabled by default (opt-in)', () => {
      expect(DEFAULT_SMS_PREFERENCES.enabled).toBe(false);
    });

    it('should subscribe to all categories by default', () => {
      expect(DEFAULT_SMS_PREFERENCES.subscribedCategories).toEqual(
        ALL_NOTIFICATION_CATEGORIES,
      );
    });
  });

  // ---------------------------------------------------------------------------
  // DEFAULT_WEBHOOK_PREFERENCES constant
  // ---------------------------------------------------------------------------

  describe('DEFAULT_WEBHOOK_PREFERENCES', () => {
    it('should have webhook disabled by default (opt-in)', () => {
      expect(DEFAULT_WEBHOOK_PREFERENCES.enabled).toBe(false);
    });

    it('should subscribe to all categories by default', () => {
      expect(DEFAULT_WEBHOOK_PREFERENCES.subscribedCategories).toEqual(
        ALL_NOTIFICATION_CATEGORIES,
      );
    });

    it('should have no URL by default', () => {
      expect(DEFAULT_WEBHOOK_PREFERENCES.url).toBeUndefined();
    });
  });
});

// =============================================================================
// Integration: NotificationService with PreferencesService
// =============================================================================

describe('NotificationService with PreferencesService', () => {
  let db: Database;
  let preferencesRepo: PreferencesRepository;
  let eventBus: EventBus;
  let preferencesService: PreferencesService;
  let notificationService: NotificationService;

  beforeEach(() => {
    db = new Database();
    preferencesRepo = new PreferencesRepository(db);
    eventBus = new EventBus();
    preferencesService = new PreferencesService(preferencesRepo, eventBus);
    notificationService = new NotificationService(eventBus, preferencesService);
    resetNotificationIdCounter();
  });

  const orderCreatedEvent: OrderCreatedEvent = {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  };

  const orderStatusChangedEvent: OrderStatusChangedEvent = {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date(),
  };

  // ---------------------------------------------------------------------------
  // Backward compatibility (no preferences configured)
  // ---------------------------------------------------------------------------

  describe('backward compatibility', () => {
    it('should send email notification when no preferences exist for user', async () => {
      await eventBus.emit(orderCreatedEvent);

      expect(notificationService.getNotificationCount()).toBe(1);
      expect(notificationService.getNotifications()[0]?.subject).toContain(
        'Order Confirmation',
      );
      expect(notificationService.getNotifications()[0]?.channel).toBe('email');
    });

    it('should send status update notifications when no preferences exist', async () => {
      await eventBus.emit(orderStatusChangedEvent);

      expect(notificationService.getNotificationCount()).toBe(1);
      expect(notificationService.getNotifications()[0]?.subject).toContain(
        'Order Update',
      );
    });

    it('should only send email (not SMS/webhook) when no preferences exist', async () => {
      await eventBus.emit(orderCreatedEvent);

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.channel).toBe('email');
    });
  });

  // ---------------------------------------------------------------------------
  // No preferences service (backward compatibility)
  // ---------------------------------------------------------------------------

  describe('without preferences service', () => {
    it('should send email notifications when no preferences service is attached', async () => {
      const freshEventBus = new EventBus();
      const freshNotifService = new NotificationService(freshEventBus);

      await freshEventBus.emit({
        ...orderCreatedEvent,
      });

      expect(freshNotifService.getNotificationCount()).toBe(1);
      expect(freshNotifService.getNotifications()[0]?.channel).toBe('email');
    });
  });

  // ---------------------------------------------------------------------------
  // Email disabled (master toggle)
  // ---------------------------------------------------------------------------

  describe('email disabled (master toggle)', () => {
    it('should suppress order confirmation when email is disabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      await eventBus.emit(orderCreatedEvent);

      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should suppress order status update when email is disabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      await eventBus.emit(orderStatusChangedEvent);

      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should suppress all notifications when email is disabled and no other channels', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      await eventBus.emit(orderCreatedEvent);
      await eventBus.emit(orderStatusChangedEvent);

      expect(notificationService.getNotificationCount()).toBe(0);
    });
  });

  // ---------------------------------------------------------------------------
  // Category-based filtering
  // ---------------------------------------------------------------------------

  describe('category-based filtering', () => {
    it('should send order confirmation when category is subscribed', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          subscribedCategories: ['order_confirmations'],
        },
      });

      await eventBus.emit(orderCreatedEvent);

      expect(notificationService.getNotificationCount()).toBe(1);
    });

    it('should suppress order confirmation when category is not subscribed', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          subscribedCategories: ['order_status_updates'],
        },
      });

      await eventBus.emit(orderCreatedEvent);

      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should send status update when category is subscribed', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          subscribedCategories: ['order_status_updates'],
        },
      });

      await eventBus.emit(orderStatusChangedEvent);

      expect(notificationService.getNotificationCount()).toBe(1);
    });

    it('should suppress status update when category is not subscribed', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          subscribedCategories: ['order_confirmations'],
        },
      });

      await eventBus.emit(orderStatusChangedEvent);

      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should allow selective categories — confirmations only', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          subscribedCategories: ['order_confirmations'],
        },
      });

      await eventBus.emit(orderCreatedEvent);
      await eventBus.emit(orderStatusChangedEvent);

      expect(notificationService.getNotificationCount()).toBe(1);
      expect(notificationService.getNotifications()[0]?.subject).toContain(
        'Order Confirmation',
      );
    });

    it('should allow selective categories — status updates only', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          subscribedCategories: ['order_status_updates'],
        },
      });

      await eventBus.emit(orderCreatedEvent);
      await eventBus.emit(orderStatusChangedEvent);

      expect(notificationService.getNotificationCount()).toBe(1);
      expect(notificationService.getNotifications()[0]?.subject).toContain(
        'Order Update',
      );
    });

    it('should suppress all notifications when subscribed categories is empty', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          subscribedCategories: [],
        },
      });

      await eventBus.emit(orderCreatedEvent);
      await eventBus.emit(orderStatusChangedEvent);

      expect(notificationService.getNotificationCount()).toBe(0);
    });
  });

  // ---------------------------------------------------------------------------
  // Multi-channel dispatch
  // ---------------------------------------------------------------------------

  describe('multi-channel dispatch', () => {
    it('should dispatch to email and SMS when both are enabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, subscribedCategories: ['order_confirmations'] },
        sms: { enabled: true, subscribedCategories: ['order_confirmations'] },
      });

      await eventBus.emit(orderCreatedEvent);

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(2);
      const channels = notifications.map((n) => n.channel).sort();
      expect(channels).toEqual(['email', 'sms']);
    });

    it('should dispatch to all three channels when all enabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true },
        sms: { enabled: true },
        webhook: { enabled: true },
      });

      await eventBus.emit(orderCreatedEvent);

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(3);
      const channels = notifications.map((n) => n.channel).sort();
      expect(channels).toEqual(['email', 'sms', 'webhook']);
    });

    it('should dispatch only to SMS when email disabled but SMS enabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
        sms: { enabled: true, subscribedCategories: ['order_confirmations'] },
      });

      await eventBus.emit(orderCreatedEvent);

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.channel).toBe('sms');
    });

    it('should respect per-channel category subscriptions', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, subscribedCategories: ['order_confirmations'] },
        sms: { enabled: true, subscribedCategories: ['order_status_updates'] },
      });

      // Order created → only email (SMS not subscribed to this category)
      await eventBus.emit(orderCreatedEvent);
      expect(notificationService.getNotificationCount()).toBe(1);
      expect(notificationService.getNotifications()[0]?.channel).toBe('email');

      notificationService.clearNotifications();

      // Status changed → only SMS (email not subscribed to this category)
      await eventBus.emit(orderStatusChangedEvent);
      expect(notificationService.getNotificationCount()).toBe(1);
      expect(notificationService.getNotifications()[0]?.channel).toBe('sms');
    });

    it('should dispatch nothing when all channels disabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
        sms: { enabled: false },
        webhook: { enabled: false },
      });

      await eventBus.emit(orderCreatedEvent);

      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should include correct content in each channel notification', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, subscribedCategories: ['order_confirmations'] },
        sms: { enabled: true, subscribedCategories: ['order_confirmations'] },
      });

      await eventBus.emit(orderCreatedEvent);

      const notifications = notificationService.getNotifications();
      for (const notification of notifications) {
        expect(notification.subject).toContain('Order Confirmation');
        expect(notification.body).toContain('Widget x2');
        expect(notification.body).toContain('$20.00');
      }
    });
  });

  // ---------------------------------------------------------------------------
  // Dynamic preference changes
  // ---------------------------------------------------------------------------

  describe('dynamic preference changes', () => {
    it('should respect updated preferences for subsequent notifications', async () => {
      // Start with all notifications enabled (email only by default)
      preferencesService.createPreferences({ userId: 'user-1' });

      await eventBus.emit(orderCreatedEvent);
      expect(notificationService.getNotificationCount()).toBe(1);

      // Disable email
      preferencesService.updatePreferences('user-1', {
        email: { enabled: false },
      });

      await eventBus.emit(orderStatusChangedEvent);
      // Should still be 1 — the second notification was suppressed
      expect(notificationService.getNotificationCount()).toBe(1);
    });

    it('should resume sending after re-enabling email', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      await eventBus.emit(orderCreatedEvent);
      expect(notificationService.getNotificationCount()).toBe(0);

      // Re-enable email
      preferencesService.updatePreferences('user-1', {
        email: { enabled: true },
      });

      await eventBus.emit(orderCreatedEvent);
      expect(notificationService.getNotificationCount()).toBe(1);
    });

    it('should resume after deleting preferences (reverts to defaults)', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      await eventBus.emit(orderCreatedEvent);
      expect(notificationService.getNotificationCount()).toBe(0);

      // Delete preferences → revert to default (email enabled)
      preferencesService.deletePreferences('user-1');

      await eventBus.emit(orderCreatedEvent);
      expect(notificationService.getNotificationCount()).toBe(1);
    });

    it('should add SMS notifications after enabling SMS', async () => {
      preferencesService.createPreferences({ userId: 'user-1' });

      await eventBus.emit(orderCreatedEvent);
      expect(notificationService.getNotificationCount()).toBe(1);
      expect(notificationService.getNotifications()[0]?.channel).toBe('email');

      // Enable SMS
      preferencesService.updatePreferences('user-1', {
        sms: { enabled: true },
      });

      notificationService.clearNotifications();
      await eventBus.emit(orderCreatedEvent);
      expect(notificationService.getNotificationCount()).toBe(2);
      const channels = notificationService.getNotifications().map((n) => n.channel).sort();
      expect(channels).toEqual(['email', 'sms']);
    });
  });

  // ---------------------------------------------------------------------------
  // setPreferencesService
  // ---------------------------------------------------------------------------

  describe('setPreferencesService', () => {
    it('should allow attaching a preferences service after construction', async () => {
      const freshEventBus = new EventBus();
      const freshNotifService = new NotificationService(freshEventBus);

      // Without preferences service, notifications should be sent (email only)
      await freshEventBus.emit(orderCreatedEvent);
      expect(freshNotifService.getNotificationCount()).toBe(1);

      // Attach preferences service with email disabled
      const freshPrefsService = new PreferencesService(preferencesRepo, freshEventBus);
      freshPrefsService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });
      freshNotifService.setPreferencesService(freshPrefsService);

      await freshEventBus.emit(orderCreatedEvent);
      // Should still be 1 — the second notification was suppressed
      expect(freshNotifService.getNotificationCount()).toBe(1);
    });

    it('should allow removing the preferences service', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      await eventBus.emit(orderCreatedEvent);
      expect(notificationService.getNotificationCount()).toBe(0);

      // Remove preferences service → fallback to email-only (backward compat)
      notificationService.setPreferencesService(undefined);

      await eventBus.emit(orderCreatedEvent);
      expect(notificationService.getNotificationCount()).toBe(1);
    });
  });

  // ---------------------------------------------------------------------------
  // Multi-user scenarios
  // ---------------------------------------------------------------------------

  describe('multi-user scenarios', () => {
    it('should enforce per-user preferences independently', async () => {
      // User 1: disable order confirmations
      preferencesService.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          subscribedCategories: ['order_status_updates'],
        },
      });

      // User 2: enable everything
      preferencesService.createPreferences({
        userId: 'user-2',
        email: {
          enabled: true,
          subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
        },
      });

      // Emit order created for user 1 (should be suppressed)
      await eventBus.emit(orderCreatedEvent);

      // Emit order created for user 2 (should be sent)
      await eventBus.emit({
        ...orderCreatedEvent,
        user: {
          ...orderCreatedEvent.user,
          id: 'user-2',
          email: 'bob@example.com',
        },
        order: { ...orderCreatedEvent.order, userId: 'user-2' },
      });

      expect(notificationService.getNotificationCount()).toBe(1);
      expect(notificationService.getNotifications()[0]?.recipient).toBe(
        'bob@example.com',
      );
    });

    it('should handle different channel configurations per user', async () => {
      // User 1: email only
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true },
        sms: { enabled: false },
      });

      // User 2: email + SMS
      preferencesService.createPreferences({
        userId: 'user-2',
        email: { enabled: true },
        sms: { enabled: true },
      });

      // Emit for user 1 → 1 notification (email)
      await eventBus.emit(orderCreatedEvent);

      // Emit for user 2 → 2 notifications (email + SMS)
      await eventBus.emit({
        ...orderCreatedEvent,
        user: {
          ...orderCreatedEvent.user,
          id: 'user-2',
          email: 'bob@example.com',
        },
        order: { ...orderCreatedEvent.order, userId: 'user-2' },
      });

      expect(notificationService.getNotificationCount()).toBe(3);
    });
  });

  // ---------------------------------------------------------------------------
  // send() public API (should NOT check preferences)
  // ---------------------------------------------------------------------------

  describe('send() public API', () => {
    it('should always send via public API regardless of preferences', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      const notification = await notificationService.send({
        recipient: 'alice@example.com',
        subject: 'Direct notification',
        body: 'This should go through regardless of preferences',
        channel: 'email',
      });

      // Public send() does not check preferences
      expect(notification.status).toBe('failed'); // No adapter registered, but it was attempted
      expect(notificationService.getNotificationCount()).toBe(1);
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validatePreferencesNotExist,
  validatePreferencesExist,
} from '../../src/validators/preferences.validator.js';
import type { UserPreferences } from '../../src/models/user-preferences.js';
import {
  ALL_NOTIFICATION_CATEGORIES,
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
} from '../../src/models/user-preferences.js';

const makePreferences = (overrides: Partial<UserPreferences> = {}): UserPreferences => ({
  id: 'user-0001',
  userId: 'user-0001',
  email: {
    enabled: true,
    frequency: 'immediate',
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  },
  sms: {
    enabled: DEFAULT_SMS_PREFERENCES.enabled,
    subscribedCategories: [...DEFAULT_SMS_PREFERENCES.subscribedCategories],
  },
  webhook: {
    enabled: DEFAULT_WEBHOOK_PREFERENCES.enabled,
    subscribedCategories: [...DEFAULT_WEBHOOK_PREFERENCES.subscribedCategories],
    url: DEFAULT_WEBHOOK_PREFERENCES.url,
  },
  createdAt: new Date(),
  updatedAt: new Date(),
  ...overrides,
});

describe('preferences.validator', () => {
  // ---------------------------------------------------------------------------
  // validatePreferencesNotExist
  // ---------------------------------------------------------------------------

  describe('validatePreferencesNotExist', () => {
    it('should not throw when no preferences exist', () => {
      expect(() =>
        validatePreferencesNotExist(undefined, 'user-0001'),
      ).not.toThrow();
    });

    it('should throw when preferences already exist', () => {
      const existing = makePreferences();
      expect(() =>
        validatePreferencesNotExist(existing, 'user-0001'),
      ).toThrow('Preferences already exist for user: user-0001');
    });

    it('should include the user ID in the error message', () => {
      const existing = makePreferences({ userId: 'user-9999' });
      expect(() =>
        validatePreferencesNotExist(existing, 'user-9999'),
      ).toThrow('user-9999');
    });
  });

  // ---------------------------------------------------------------------------
  // validatePreferencesExist
  // ---------------------------------------------------------------------------

  describe('validatePreferencesExist', () => {
    it('should not throw when preferences exist', () => {
      const existing = makePreferences();
      expect(() =>
        validatePreferencesExist(existing, 'user-0001'),
      ).not.toThrow();
    });

    it('should throw when preferences are undefined', () => {
      expect(() =>
        validatePreferencesExist(undefined, 'user-0001'),
      ).toThrow('Preferences not found for user: user-0001');
    });

    it('should include the user ID in the error message', () => {
      expect(() =>
        validatePreferencesExist(undefined, 'user-9999'),
      ).toThrow('user-9999');
    });
  });
});

